import anthropic
import subprocess
import json

client = anthropic.Anthropic()  # reads ANTHROPIC_API_KEY from env

# ─── Tool definitions (sent to the model as a schema) ─────────────────
TOOL_DEFS = [
    {
        "name": "run_python",
        "description": "Execute a Python snippet and return stdout + stderr.",
        "input_schema": {
            "type": "object",
            "properties": {
                "code": {"type": "string", "description": "Python code to run"}
            },
            "required": ["code"],
        },
    },
    {
        "name": "read_file",
        "description": "Read a text file and return its contents.",
        "input_schema": {
            "type": "object",
            "properties": {
                "path": {"type": "string", "description": "File path to read"}
            },
            "required": ["path"],
        },
    },
]

# ─── Tool executor ────────────────────────────────────────────────────
def execute_tool(name: str, inputs: dict) -> str:
    if name == "run_python":
        result = subprocess.run(
            ["python3", "-c", inputs["code"]],
            capture_output=True, text=True, timeout=10
        )
        return result.stdout + result.stderr
    elif name == "read_file":
        try:
            with open(inputs["path"]) as f:
                return f.read()
        except FileNotFoundError:
            return f"File not found: {inputs['path']}"
    return f"Unknown tool: {name}"

# ─── Agent loop ───────────────────────────────────────────────────────
def run_agent(goal: str, max_steps: int = 10) -> str:
    messages = [{"role": "user", "content": goal}]

    for step in range(max_steps):
        response = client.messages.create(
            model="claude-sonnet-4-6",
            max_tokens=4096,
            tools=TOOL_DEFS,
            messages=messages,
        )

        # Append assistant response to conversation
        messages.append({"role": "assistant", "content": response.content})

        if response.stop_reason == "end_turn":
            # Model is done — extract text from the final content block
            for block in response.content:
                if hasattr(block, "text"):
                    return block.text
            return "(no text response)"

        # Process tool calls
        tool_results = []
        for block in response.content:
            if block.type == "tool_use":
                print(f"  → Calling {block.name}({block.input})")
                result = execute_tool(block.name, block.input)
                print(f"  ← {result[:200]}")
                tool_results.append({
                    "type": "tool_result",
                    "tool_use_id": block.id,
                    "content": result,
                })

        if tool_results:
            messages.append({"role": "user", "content": tool_results})

    return "Max steps reached without final answer."


if __name__ == "__main__":
    answer = run_agent(
        "Write a Python snippet that computes the first 10 Fibonacci numbers, "
        "then run it and tell me the result."
    )
    print("\nAgent answer:", answer)
